import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.Scanner;
import org.json.JSONArray;
import org.json.JSONObject;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            ArrayList<JSONObject> records = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                String line = scanner.next();
                records.add(new JSONObject(line));
            }
            int queryType = scanner.nextInt();
            if (queryType == 1) {
                String criteria = scanner.next();
                if (criteria.equals("name")) {
                    Collections.sort(records, new Comparator<JSONObject>() {
                        @Override
                        public int compare(JSONObject a, JSONObject b) {
                            return a.getString("name").compareTo(b.getString("name"));
                        }
                    });
                }
                for (int i = 0; i < N; i++) {
                    System.out.println(records.get(i));
                }
            } else if (queryType == 2) {
                int id = scanner.nextInt();
                String line = scanner.next();
                JSONObject updatedRecord = new JSONObject(line);
                for (int i = 0; i < N; i++) {
                    if (records.get(i).getInt("id") == id) {
                        records.set(i, updatedRecord);
                        break;
                    }
                }
                for (int i = 0; i < N; i++) {
                    System.out.println(records.get(i));
                }
            } else if (queryType == 3) {
                String query = scanner.next();
                for (int i = 0; i < N; i++) {
                    if (records.get(i).getString("name").contains(query)) {
                        System.out.println(records.get(i));
                    }
                }
            } else if (queryType == 4) {
                int id = scanner.nextInt();
                for (int i = 0; i < N; i++) {
                    if (records.get(i).getInt("id") == id) {
                        records.remove(i);
                        break;
                    }
                }
                for (int i = 0; i < records.size(); i++) {
                    System.out.println(records.get(i));
                }
            }
        }
    }
}

